#include <bits/stdc++.h>
using namespace std;

const int N=210;

int n,m,f[N][N],match[N],ans;
bool vis[N];
vector<int> g[N];

int dfs(int x){
    for(int y:g[x])
        if(!vis[y]){
            vis[y]=1;
            if(!match[y] || dfs(match[y])){
                match[y]=x;
                return true;
            }
        }
    return false;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        f[u][v]=1;
    }
    for(int i=1;i<=n;i++)
        f[i][i]=1;
    for(int k=1;k<=n;k++)
        for(int i=1;i<=n;i++)
            for(int j=1;j<=n;j++)
                f[i][j]=max(f[i][j],(f[i][k]&f[k][j]));
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            if(i!=j && f[i][j])
                g[i].push_back(j);
    int ans=n;
    for(int i=1;i<=n;i++){
        memset(vis,0,sizeof(vis));
        if(dfs(i))
            ans--;
    }
    printf("%d",ans);
    return 0;
}
